using sv_0d274a7e46324efc87255060375daa5d.Models;

namespace sv_0d274a7e46324efc87255060375daa5d.Services;

public class InMemoryChatService : IChatService
{
    private readonly List<Channel> _channels;
    private readonly List<Message> _messages;
    private int _nextMessageId;

    public InMemoryChatService()
    {
        _channels = new List<Channel>
        {
            new(1, "general", "General discussion for the team", 3),
            new(2, "engineering", "Engineering updates and tech talk", 0),
            new(3, "design", "Design reviews and feedback", 1),
            new(4, "random", "Off-topic and fun stuff", 5),
            new(5, "announcements", "Important team announcements", 0)
        };

        _messages = new List<Message>
        {
            new(1, 1, "Alice", "Hey everyone! Welcome to the new team chat.", DateTime.UtcNow.AddHours(-5), null, new List<Reaction> { new("👍", new List<string> { "Bob", "Carol" }), new("🎉", new List<string> { "Dave" }) }),
            new(2, 1, "Bob", "Thanks Alice! Excited to be here.", DateTime.UtcNow.AddHours(-4), null, new List<Reaction>()),
            new(3, 1, "Carol", "This looks great! Love the new setup.", DateTime.UtcNow.AddHours(-4), null, new List<Reaction> { new("❤️", new List<string> { "Alice" }) }),
            new(4, 1, "Dave", "Agreed, really nice!", DateTime.UtcNow.AddHours(-3), 1, new List<Reaction>()),
            new(5, 1, "Alice", "Let's use this for all team comms going forward.", DateTime.UtcNow.AddHours(-3), 1, new List<Reaction>()),
            new(6, 1, "Bob", "Has anyone tried the thread feature?", DateTime.UtcNow.AddHours(-2), null, new List<Reaction>()),
            new(7, 1, "Carol", "Yes! It works well.", DateTime.UtcNow.AddHours(-1), 6, new List<Reaction> { new("👍", new List<string> { "Bob" }) }),
            new(8, 1, "Dave", "Shipping the new build today.", DateTime.UtcNow.AddMinutes(-45), null, new List<Reaction> { new("🔥", new List<string> { "Alice", "Bob" }) }),
            new(9, 1, "Alice", "Great work Dave! 🚀", DateTime.UtcNow.AddMinutes(-30), null, new List<Reaction>()),
            new(10, 1, "Bob", "Let me know if you need help with QA.", DateTime.UtcNow.AddMinutes(-15), null, new List<Reaction>()),
            new(11, 2, "Carol", "New PR is up for the auth module.", DateTime.UtcNow.AddHours(-3), null, new List<Reaction> { new("👀", new List<string> { "Dave" }) }),
            new(12, 2, "Dave", "I'll review it this afternoon.", DateTime.UtcNow.AddHours(-2), 11, new List<Reaction>()),
            new(13, 2, "Alice", "Don't forget to update the API docs.", DateTime.UtcNow.AddHours(-1), null, new List<Reaction>()),
            new(14, 3, "Bob", "New mockups for the dashboard are ready.", DateTime.UtcNow.AddHours(-6), null, new List<Reaction> { new("🎉", new List<string> { "Carol", "Alice" }) }),
            new(15, 3, "Carol", "Looking good! A few notes on spacing.", DateTime.UtcNow.AddHours(-5), 14, new List<Reaction>()),
            new(16, 4, "Dave", "Anyone up for lunch?", DateTime.UtcNow.AddMinutes(-90), null, new List<Reaction> { new("😂", new List<string> { "Alice" }) }),
        };

        _nextMessageId = _messages.Count + 1;
    }

    public Task<List<Channel>> GetChannelsAsync()
    {
        return Task.FromResult(_channels.Select(c => c).ToList());
    }

    public Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take)
    {
        var msgs = _messages
            .Where(m => m.ChannelId == channelId)
            .OrderBy(m => m.SentAt)
            .Skip(skip)
            .Take(take)
            .ToList();
        return Task.FromResult(msgs);
    }

    public Task<Message> SendMessageAsync(int channelId, string content, int? replyToId)
    {
        var msg = new Message(_nextMessageId++, channelId, "You", content, DateTime.UtcNow, replyToId, new List<Reaction>());
        _messages.Add(msg);
        return Task.FromResult(msg);
    }

    public Task<List<Message>> GetThreadAsync(int rootMessageId)
    {
        var root = _messages.FirstOrDefault(m => m.Id == rootMessageId);
        var replies = _messages.Where(m => m.ReplyToId == rootMessageId).OrderBy(m => m.SentAt).ToList();
        var result = new List<Message>();
        if (root != null) result.Add(root);
        result.AddRange(replies);
        return Task.FromResult(result);
    }

    public Task AddReactionAsync(int messageId, string emoji)
    {
        var msg = _messages.FirstOrDefault(m => m.Id == messageId);
        if (msg != null)
        {
            var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == emoji);
            if (existing != null)
            {
                if (!existing.Users.Contains("You"))
                    existing.Users.Add("You");
            }
            else
            {
                msg.Reactions.Add(new Reaction(emoji, new List<string> { "You" }));
            }
        }
        return Task.CompletedTask;
    }

    public Task MarkChannelReadAsync(int channelId)
    {
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            _channels[idx] = _channels[idx] with { UnreadCount = 0 };
        }
        return Task.CompletedTask;
    }
}

@page "/chat"
@rendermode InteractiveServer
@inject IChatService ChatService

<PageTitle>Team Chat</PageTitle>

<div class="chat-container">
    @* Left Sidebar *@
    <div class="sidebar">
        <div class="sidebar-header">
            <h3>Channels</h3>
        </div>
        <div class="channel-list">
            @if (channels != null)
            {
                @foreach (var channel in channels)
                {
                    <div class="channel-item @(selectedChannel?.Id == channel.Id ? "active" : "")"
                         @onclick="() => SelectChannel(channel)">
                        <div class="channel-name"># @channel.Name</div>
                        <div class="channel-desc">@TruncateText(channel.Description, 30)</div>
                        @if (channel.UnreadCount > 0)
                        {
                            <span class="unread-badge">@channel.UnreadCount</span>
                        }
                    </div>
                }
            }
        </div>
    </div>

    @* Main Message Area *@
    <div class="main-area @(threadRootMessage != null ? "with-thread" : "")">
        @if (selectedChannel != null)
        {
            <div class="main-header">
                <h2># @selectedChannel.Name</h2>
                <span class="header-desc">@selectedChannel.Description</span>
            </div>
            <div class="message-list">
                @if (hasMoreMessages)
                {
                    <div class="load-more-container">
                        <button class="load-more-btn" @onclick="LoadMoreMessages" disabled="@isLoading">
                            @(isLoading ? "Loading..." : "Load more messages")
                        </button>
                    </div>
                }
                @if (messages != null)
                {
                    @foreach (var msg in messages)
                    {
                        <div class="message @(hoveredMessageId == msg.Id ? "hovered" : "")"
                             @onmouseenter="() => hoveredMessageId = msg.Id"
                             @onmouseleave="OnMessageMouseLeave">
                            <div class="message-header">
                                <span class="msg-author">@msg.Author</span>
                                <span class="msg-time">@FormatRelativeTime(msg.SentAt)</span>
                            </div>
                            @if (msg.ReplyToId != null)
                            {
                                var parent = messages.FirstOrDefault(m => m.Id == msg.ReplyToId);
                                <div class="reply-indicator">
                                    ↩ in reply to <strong>@(parent?.Author ?? "...")</strong>
                                </div>
                            }
                            <div class="msg-content">@msg.Content</div>

                            @if (msg.Reactions.Count > 0)
                            {
                                <div class="reactions">
                                    @foreach (var reaction in msg.Reactions)
                                    {
                                        <button class="reaction-badge" @onclick="() => OnReactionClick(msg.Id, reaction.Emoji)">
                                            @reaction.Emoji @reaction.Users.Count
                                        </button>
                                    }
                                </div>
                            }

                            @if (threadSummaries.ContainsKey(msg.Id))
                            {
                                var summary = threadSummaries[msg.Id];
                                <div class="thread-link" @onclick="() => OpenThread(msg)">
                                    💬 @summary.ReplyCount @(summary.ReplyCount == 1 ? "reply" : "replies")
                                    <span class="thread-time">Last reply @FormatRelativeTime(summary.LastReplyAt)</span>
                                </div>
                            }

                            @if (hoveredMessageId == msg.Id)
                            {
                                <div class="hover-actions">
                                    <button class="action-btn" title="Reply" @onclick="() => OpenThread(msg)">💬</button>
                                    <button class="action-btn" title="React" @onclick="() => ToggleEmojiPicker(msg.Id)">😀</button>
                                </div>

                                @if (showEmojiPickerForMessageId == msg.Id)
                                {
                                    <div class="emoji-picker">
                                        @foreach (var emoji in emojiOptions)
                                        {
                                            <button class="emoji-btn" @onclick="() => OnReactionClick(msg.Id, emoji)">@emoji</button>
                                        }
                                    </div>
                                }
                            }
                        </div>
                    }
                }
            </div>
            <div class="message-input">
                <textarea @bind="newMessage" placeholder="Message #@selectedChannel.Name" rows="2"></textarea>
                <button class="send-btn" @onclick="SendMessage" disabled="@(string.IsNullOrWhiteSpace(newMessage))">Send</button>
            </div>
        }
        else
        {
            <div class="no-channel">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @* Right Thread Panel *@
    @if (threadRootMessage != null)
    {
        <div class="thread-panel">
            <div class="thread-header">
                <h3>Thread</h3>
                <button class="close-btn" @onclick="CloseThread">✕</button>
            </div>
            <div class="thread-root-quote">
                <span class="msg-author">@threadRootMessage.Author</span>
                <div class="msg-content">@threadRootMessage.Content</div>
            </div>
            <div class="thread-replies">
                @if (threadMessages != null)
                {
                    @foreach (var reply in threadMessages.Where(m => m.Id != threadRootMessage.Id))
                    {
                        <div class="message">
                            <div class="message-header">
                                <span class="msg-author">@reply.Author</span>
                                <span class="msg-time">@FormatRelativeTime(reply.SentAt)</span>
                            </div>
                            <div class="msg-content">@reply.Content</div>
                            @if (reply.Reactions.Count > 0)
                            {
                                <div class="reactions">
                                    @foreach (var reaction in reply.Reactions)
                                    {
                                        <button class="reaction-badge" @onclick="() => OnReactionClick(reply.Id, reaction.Emoji)">
                                            @reaction.Emoji @reaction.Users.Count
                                        </button>
                                    }
                                </div>
                            }
                        </div>
                    }
                }
            </div>
            <div class="message-input">
                <textarea @bind="threadReply" placeholder="Reply in thread..." rows="2"></textarea>
                <button class="send-btn" @onclick="SendThreadReply" disabled="@(string.IsNullOrWhiteSpace(threadReply))">Reply</button>
            </div>
        </div>
    }
</div>

@code {
    private List<Channel>? channels;
    private Channel? selectedChannel;
    private List<Message> messages = new();
    private int skip;
    private const int take = 30;
    private bool hasMoreMessages;
    private string newMessage = string.Empty;
    private Message? threadRootMessage;
    private List<Message>? threadMessages;
    private string threadReply = string.Empty;
    private int? hoveredMessageId;
    private int? showEmojiPickerForMessageId;
    private bool isLoading;
    private Dictionary<int, ThreadSummary> threadSummaries = new();

    private static readonly string[] emojiOptions = { "👍", "❤️", "😂", "🎉", "👀", "🔥" };

    protected override async Task OnInitializedAsync()
    {
        try
        {
            channels = await ChatService.GetChannelsAsync();
            if (channels?.Count > 0)
            {
                await SelectChannel(channels[0]);
            }
        }
        catch
        {
            channels = new();
        }
    }

    private async Task SelectChannel(Channel channel)
    {
        try
        {
            selectedChannel = channel;
            skip = 0;
            messages = new();
            threadRootMessage = null;
            threadMessages = null;

            await ChatService.MarkChannelReadAsync(channel.Id);
            channels = await ChatService.GetChannelsAsync();

            var loaded = await ChatService.GetMessagesAsync(channel.Id, skip, take);
            messages = loaded;
            hasMoreMessages = loaded.Count >= take;
            BuildThreadSummaries();
        }
        catch { }
    }

    private async Task LoadMoreMessages()
    {
        if (isLoading || selectedChannel == null) return;
        try
        {
            isLoading = true;
            skip += take;
            var older = await ChatService.GetMessagesAsync(selectedChannel.Id, skip, take);
            hasMoreMessages = older.Count >= take;
            messages.InsertRange(0, older);
            BuildThreadSummaries();
        }
        catch { }
        finally
        {
            isLoading = false;
        }
    }

    private async Task SendMessage()
    {
        if (string.IsNullOrWhiteSpace(newMessage) || selectedChannel == null) return;
        try
        {
            var msg = await ChatService.SendMessageAsync(selectedChannel.Id, newMessage.Trim(), null);
            messages.Add(msg);
            newMessage = string.Empty;
        }
        catch { }
    }

    private async Task OpenThread(Message rootMsg)
    {
        try
        {
            // Find the actual root if this message is a reply itself
            var actualRoot = rootMsg.ReplyToId != null
                ? messages.FirstOrDefault(m => m.Id == rootMsg.ReplyToId) ?? rootMsg
                : rootMsg;

            threadRootMessage = actualRoot;
            threadMessages = await ChatService.GetThreadAsync(actualRoot.Id);
            threadReply = string.Empty;
            showEmojiPickerForMessageId = null;
        }
        catch { }
    }

    private void CloseThread()
    {
        threadRootMessage = null;
        threadMessages = null;
    }

    private async Task SendThreadReply()
    {
        if (string.IsNullOrWhiteSpace(threadReply) || threadRootMessage == null || selectedChannel == null) return;
        try
        {
            var reply = await ChatService.SendMessageAsync(selectedChannel.Id, threadReply.Trim(), threadRootMessage.Id);
            threadMessages?.Add(reply);
            messages.Add(reply);
            threadReply = string.Empty;
            BuildThreadSummaries();
        }
        catch { }
    }

    private async Task OnReactionClick(int messageId, string emoji)
    {
        try
        {
            await ChatService.AddReactionAsync(messageId, emoji);
            showEmojiPickerForMessageId = null;

            // Refresh messages to reflect reaction changes
            if (selectedChannel != null)
            {
                var refreshed = await ChatService.GetMessagesAsync(selectedChannel.Id, 0, skip + take);
                messages = refreshed;
            }
            if (threadRootMessage != null)
            {
                threadMessages = await ChatService.GetThreadAsync(threadRootMessage.Id);
            }
        }
        catch { }
    }

    private void ToggleEmojiPicker(int messageId)
    {
        showEmojiPickerForMessageId = showEmojiPickerForMessageId == messageId ? null : messageId;
    }

    private void OnMessageMouseLeave()
    {
        hoveredMessageId = null;
        showEmojiPickerForMessageId = null;
    }

    private void BuildThreadSummaries()
    {
        threadSummaries = new();
        foreach (var msg in messages.Where(m => m.ReplyToId != null))
        {
            var rootId = msg.ReplyToId!.Value;
            if (threadSummaries.TryGetValue(rootId, out var existing))
            {
                threadSummaries[rootId] = existing with
                {
                    ReplyCount = existing.ReplyCount + 1,
                    LastReplyAt = msg.SentAt > existing.LastReplyAt ? msg.SentAt : existing.LastReplyAt
                };
            }
            else
            {
                threadSummaries[rootId] = new ThreadSummary(rootId, 1, msg.SentAt);
            }
        }
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours} {((int)diff.TotalHours == 1 ? "hour" : "hours")} ago";
        if (diff.TotalDays < 2) return "yesterday";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays} days ago";
        return sentAt.ToString("MMM d");
    }

    private static string TruncateText(string text, int maxLength)
    {
        return text.Length <= maxLength ? text : text[..maxLength] + "…";
    }
}

