1. @page "/chat"
2. @rendermode InteractiveServer
3. @inject IChatService ChatService
4. 
5. <PageTitle>Team Chat</PageTitle>
6. 
7. <div class="chat-container">
8.     @* Left Sidebar *@
9.     <div class="sidebar">
10.         <div class="sidebar-header">
11.             <h3>Channels</h3>
12.         </div>
13.         <div class="channel-list">
14.             @if (channels != null)
15.             {
16.                 @foreach (var channel in channels)
17.                 {
18.                     <div class="channel-item @(selectedChannel?.Id == channel.Id ? "active" : "")"
19.                          @onclick="() => SelectChannel(channel)">
20.                         <div class="channel-name"># @channel.Name</div>
21.                         <div class="channel-desc">@TruncateText(channel.Description, 30)</div>
22.                         @if (channel.UnreadCount > 0)
23.                         {
24.                             <span class="unread-badge">@channel.UnreadCount</span>
25.                         }
26.                     </div>
27.                 }
28.             }
29.         </div>
30.     </div>
31. 
32.     @* Main Message Area *@
33.     <div class="main-area @(threadRootMessage != null ? "with-thread" : "")">
34.         @if (selectedChannel != null)
35.         {
36.             <div class="main-header">
37.                 <h2># @selectedChannel.Name</h2>
38.                 <span class="header-desc">@selectedChannel.Description</span>
39.             </div>
40.             <div class="message-list">
41.                 @if (hasMoreMessages)
42.                 {
43.                     <div class="load-more-container">
44.                         <button class="load-more-btn" @onclick="LoadMoreMessages" disabled="@isLoading">
45.                             @(isLoading ? "Loading..." : "Load more messages")
46.                         </button>
47.                     </div>
48.                 }
49.                 @if (messages != null)
50.                 {
51.                     @foreach (var msg in messages)
52.                     {
53.                         <div class="message @(hoveredMessageId == msg.Id ? "hovered" : "")"
54.                              @onmouseenter="() => hoveredMessageId = msg.Id"
55.                              @onmouseleave="OnMessageMouseLeave">
56.                             <div class="message-header">
57.                                 <span class="msg-author">@msg.Author</span>
58.                                 <span class="msg-time">@FormatRelativeTime(msg.SentAt)</span>
59.                             </div>
60.                             @if (msg.ReplyToId != null)
61.                             {
62.                                 var parent = messages.FirstOrDefault(m => m.Id == msg.ReplyToId);
63.                                 <div class="reply-indicator">
64.                                     ↩ in reply to <strong>@(parent?.Author ?? "...")</strong>
65.                                 </div>
66.                             }
67.                             <div class="msg-content">@msg.Content</div>
68. 
69.                             @if (msg.Reactions.Count > 0)
70.                             {
71.                                 <div class="reactions">
72.                                     @foreach (var reaction in msg.Reactions)
73.                                     {
74.                                         <button class="reaction-badge" @onclick="() => OnReactionClick(msg.Id, reaction.Emoji)">
75.                                             @reaction.Emoji @reaction.Users.Count
76.                                         </button>
77.                                     }
78.                                 </div>
79.                             }
80. 
81.                             @if (threadSummaries.ContainsKey(msg.Id))
82.                             {
83.                                 var summary = threadSummaries[msg.Id];
84.                                 <div class="thread-link" @onclick="() => OpenThread(msg)">
85.                                     💬 @summary.ReplyCount @(summary.ReplyCount == 1 ? "reply" : "replies")
86.                                     <span class="thread-time">Last reply @FormatRelativeTime(summary.LastReplyAt)</span>
87.                                 </div>
88.                             }
89. 
90.                             @if (hoveredMessageId == msg.Id)
91.                             {
92.                                 <div class="hover-actions">
93.                                     <button class="action-btn" title="Reply" @onclick="() => OpenThread(msg)">💬</button>
94.                                     <button class="action-btn" title="React" @onclick="() => ToggleEmojiPicker(msg.Id)">😀</button>
95.                                 </div>
96. 
97.                                 @if (showEmojiPickerForMessageId == msg.Id)
98.                                 {
99.                                     <div class="emoji-picker">
100.                                         @foreach (var emoji in emojiOptions)
101.                                         {
102.                                             <button class="emoji-btn" @onclick="() => OnReactionClick(msg.Id, emoji)">@emoji</button>
103.                                         }
104.                                     </div>
105.                                 }
106.                             }
107.                         </div>
108.                     }
109.                 }
110.             </div>
111.             <div class="message-input">
112.                 <textarea @bind="newMessage" placeholder="Message #@selectedChannel.Name" rows="2"></textarea>
113.                 <button class="send-btn" @onclick="SendMessage" disabled="@(string.IsNullOrWhiteSpace(newMessage))">Send</button>
114.             </div>
115.         }
116.         else
117.         {
118.             <div class="no-channel">
119.                 <p>Select a channel to start chatting</p>
120.             </div>
121.         }
122.     </div>
123. 
124.     @* Right Thread Panel *@
125.     @if (threadRootMessage != null)
126.     {
127.         <div class="thread-panel">
128.             <div class="thread-header">
129.                 <h3>Thread</h3>
130.                 <button class="close-btn" @onclick="CloseThread">✕</button>
131.             </div>
132.             <div class="thread-root-quote">
133.                 <span class="msg-author">@threadRootMessage.Author</span>
134.                 <div class="msg-content">@threadRootMessage.Content</div>
135.             </div>
136.             <div class="thread-replies">
137.                 @if (threadMessages != null)
138.                 {
139.                     @foreach (var reply in threadMessages.Where(m => m.Id != threadRootMessage.Id))
140.                     {
141.                         <div class="message">
142.                             <div class="message-header">
143.                                 <span class="msg-author">@reply.Author</span>
144.                                 <span class="msg-time">@FormatRelativeTime(reply.SentAt)</span>
145.                             </div>
146.                             <div class="msg-content">@reply.Content</div>
147.                             @if (reply.Reactions.Count > 0)
148.                             {
149.                                 <div class="reactions">
150.                                     @foreach (var reaction in reply.Reactions)
151.                                     {
152.                                         <button class="reaction-badge" @onclick="() => OnReactionClick(reply.Id, reaction.Emoji)">
153.                                             @reaction.Emoji @reaction.Users.Count
154.                                         </button>
155.                                     }
156.                                 </div>
157.                             }
158.                         </div>
159.                     }
160.                 }
161.             </div>
162.             <div class="message-input">
163.                 <textarea @bind="threadReply" placeholder="Reply in thread..." rows="2"></textarea>
164.                 <button class="send-btn" @onclick="SendThreadReply" disabled="@(string.IsNullOrWhiteSpace(threadReply))">Reply</button>
165.             </div>
166.         </div>
167.     }
168. </div>
169. 
170. @code {
171.     private List<Channel>? channels;
172.     private Channel? selectedChannel;
173.     private List<Message> messages = new();
174.     private int skip;
175.     private const int take = 30;
176.     private bool hasMoreMessages;
177.     private string newMessage = string.Empty;
178.     private Message? threadRootMessage;
179.     private List<Message>? threadMessages;
180.     private string threadReply = string.Empty;
181.     private int? hoveredMessageId;
182.     private int? showEmojiPickerForMessageId;
183.     private bool isLoading;
184.     private Dictionary<int, ThreadSummary> threadSummaries = new();
185. 
186.     private static readonly string[] emojiOptions = { "👍", "❤️", "😂", "🎉", "👀", "🔥" };
187. 
188.     protected override async Task OnInitializedAsync()
189.     {
190.         try
191.         {
192.             channels = await ChatService.GetChannelsAsync();
193.             if (channels?.Count > 0)
194.             {
195.                 await SelectChannel(channels[0]);
196.             }
197.         }
198.         catch
199.         {
200.             channels = new();
201.         }
202.     }
203. 
204.     private async Task SelectChannel(Channel channel)
205.     {
206.         try
207.         {
208.             selectedChannel = channel;
209.             skip = 0;
210.             messages = new();
211.             threadRootMessage = null;
212.             threadMessages = null;
213. 
214.             await ChatService.MarkChannelReadAsync(channel.Id);
215.             channels = await ChatService.GetChannelsAsync();
216. 
217.             var loaded = await ChatService.GetMessagesAsync(channel.Id, skip, take);
218.             messages = loaded;
219.             hasMoreMessages = loaded.Count >= take;
220.             BuildThreadSummaries();
221.         }
222.         catch { }
223.     }
224. 
225.     private async Task LoadMoreMessages()
226.     {
227.         if (isLoading || selectedChannel == null) return;
228.         try
229.         {
230.             isLoading = true;
231.             skip += take;
232.             var older = await ChatService.GetMessagesAsync(selectedChannel.Id, skip, take);
233.             hasMoreMessages = older.Count >= take;
234.             messages.InsertRange(0, older);
235.             BuildThreadSummaries();
236.         }
237.         catch { }
238.         finally
239.         {
240.             isLoading = false;
241.         }
242.     }
243. 
244.     private async Task SendMessage()
245.     {
246.         if (string.IsNullOrWhiteSpace(newMessage) || selectedChannel == null) return;
247.         try
248.         {
249.             var msg = await ChatService.SendMessageAsync(selectedChannel.Id, newMessage.Trim(), null);
250.             messages.Add(msg);
251.             newMessage = string.Empty;
252.         }
253.         catch { }
254.     }
255. 
256.     private async Task OpenThread(Message rootMsg)
257.     {
258.         try
259.         {
260.             // Find the actual root if this message is a reply itself
261.             var actualRoot = rootMsg.ReplyToId != null
262.                 ? messages.FirstOrDefault(m => m.Id == rootMsg.ReplyToId) ?? rootMsg
263.                 : rootMsg;
264. 
265.             threadRootMessage = actualRoot;
266.             threadMessages = await ChatService.GetThreadAsync(actualRoot.Id);
267.             threadReply = string.Empty;
268.             showEmojiPickerForMessageId = null;
