 @code {
     private List<Channel>? channels;
     private Channel? selectedChannel;
     private List<Message> messages = new();
     private int skip;
     private const int take = 30;
     private bool hasMoreMessages;
     private string newMessage = string.Empty;
     private Message? threadRootMessage;
     private List<Message>? threadMessages;
     private string threadReply = string.Empty;
     private int? hoveredMessageId;
     private int? showEmojiPickerForMessageId;
     private bool isLoading;
     private Dictionary<int, ThreadSummary> threadSummaries = new();

     private static readonly string[] emojiOptions = { "👍", "❤️", "😂", "🎉", "👀", "🔥" };

     protected override async Task OnInitializedAsync()
     {
         try
         {
             channels = await ChatService.GetChannelsAsync();
             if (channels?.Count > 0)
             {
                 await SelectChannel(channels[0]);
             }
         }
         catch
         {
             channels = new();
         }
     }

     private async Task SelectChannel(Channel channel)
     {
         try
         {
             selectedChannel = channel;
             skip = 0;
             messages = new();
             threadRootMessage = null;
             threadMessages = null;

             await ChatService.MarkChannelReadAsync(channel.Id);
             channels = await ChatService.GetChannelsAsync();

             var loaded = await ChatService.GetMessagesAsync(channel.Id, skip, take);
             messages = loaded;
             hasMoreMessages = loaded.Count >= take;
             BuildThreadSummaries();
         }
         catch { }
     }

     private async Task LoadMoreMessages()
     {
         if (isLoading || selectedChannel == null) return;
         try
         {
             isLoading = true;
             skip += take;
             var older = await ChatService.GetMessagesAsync(selectedChannel.Id, skip, take);
             hasMoreMessages = older.Count >= take;
             messages.InsertRange(0, older);
             BuildThreadSummaries();
         }
         catch { }
         finally
         {
             isLoading = false;
         }
     }

     private async Task SendMessage()
     {
         if (string.IsNullOrWhiteSpace(newMessage) || selectedChannel == null) return;
         try
         {
             var msg = await ChatService.SendMessageAsync(selectedChannel.Id, newMessage.Trim(), null);
             messages.Add(msg);
             newMessage = string.Empty;
         }
         catch { }
     }

     private async Task OpenThread(Message rootMsg)
     {
         try
         {
             // Find the actual root if this message is a reply itself
             var actualRoot = rootMsg.ReplyToId != null
                 ? messages.FirstOrDefault(m => m.Id == rootMsg.ReplyToId) ?? rootMsg
                 : rootMsg;

             threadRootMessage = actualRoot;
             threadMessages = await ChatService.GetThreadAsync(actualRoot.Id);
             threadReply = string.Empty;
             showEmojiPickerForMessageId = null;
         }
         catch { }
     }

     private void CloseThread()
     {
         threadRootMessage = null;
         threadMessages = null;
     }

     private async Task SendThreadReply()
     {
         if (string.IsNullOrWhiteSpace(threadReply) || threadRootMessage == null || selectedChannel == null) return;
         try
         {
             var reply = await ChatService.SendMessageAsync(selectedChannel.Id, threadReply.Trim(), threadRootMessage.Id);
             threadMessages?.Add(reply);
             messages.Add(reply);
             threadReply = string.Empty;
             BuildThreadSummaries();
         }
         catch { }
     }

     private async Task OnReactionClick(int messageId, string emoji)
     {
         try
         {
             await ChatService.AddReactionAsync(messageId, emoji);
             showEmojiPickerForMessageId = null;

             // Refresh messages to reflect reaction changes
             if (selectedChannel != null)
             {
                 var refreshed = await ChatService.GetMessagesAsync(selectedChannel.Id, 0, skip + take);
                 messages = refreshed;
             }
             if (threadRootMessage != null)
             {
                 threadMessages = await ChatService.GetThreadAsync(threadRootMessage.Id);
             }
         }
         catch { }
     }

     private void ToggleEmojiPicker(int messageId)
     {
         showEmojiPickerForMessageId = showEmojiPickerForMessageId == messageId ? null : messageId;
     }

     private void OnMessageMouseLeave()
     {
         hoveredMessageId = null;
         showEmojiPickerForMessageId = null;
     }

     private void BuildThreadSummaries()
     {
         threadSummaries = new();
         foreach (var msg in messages.Where(m => m.ReplyToId != null))
         {
             var rootId = msg.ReplyToId!.Value;
             if (threadSummaries.TryGetValue(rootId, out var existing))
             {
                 threadSummaries[rootId] = existing with
                 {
                     ReplyCount = existing.ReplyCount + 1,
                     LastReplyAt = msg.SentAt > existing.LastReplyAt ? msg.SentAt : existing.LastReplyAt
                 };
             }
             else
             {
                 threadSummaries[rootId] = new ThreadSummary(rootId, 1, msg.SentAt);
             }
         }
     }

     private static string FormatRelativeTime(DateTime sentAt)
     {
         var diff = DateTime.UtcNow - sentAt;
         if (diff.TotalSeconds < 60) return "just now";
         if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
         if (diff.TotalHours < 24) return $"{(int)diff.TotalHours} {((int)diff.TotalHours == 1 ? "hour" : "hours")} ago";
         if (diff.TotalDays < 2) return "yesterday";
         if (diff.TotalDays < 7) return $"{(int)diff.TotalDays} days ago";
         return sentAt.ToString("MMM d");
     }

     private static string TruncateText(string text, int maxLength)
     {
         return text.Length <= maxLength ? text : text[..maxLength] + "…";
     }
 }

